// ─────────────── State ─────────────────────────────────────
let allEvents = [];

// Backfill missing context on tool_call/error events from their session peers
function enrichEvents(events) {
  // Build lookup: for each user_id, sorted list of context-bearing events
  const contextByUser = {};
  events.forEach(e => {
    // FIX: Changed || to && so only fully formed events provide context
    if (e.entity_type && e.model) {
      if (!contextByUser[e.user_id]) contextByUser[e.user_id] = [];
      contextByUser[e.user_id].push(e);
    }
  });

  // Sort each user's context events by timestamp
  Object.values(contextByUser).forEach(arr => arr.sort((a, b) => (a.timestamp_ms || 0) - (b.timestamp_ms || 0)));
  return events.map(e => {
    // If it's already complete, return it
    if (e.entity_type && e.model) return e;
    const peers = contextByUser[e.user_id];
    if (!peers || !peers.length) return e;

    // Find the most recent context event at or before this one
    let ctx = null;
    for (const p of peers) {
      if ((p.timestamp_ms || 0) <= (e.timestamp_ms || 0)) ctx = p;else break;
    }
    if (!ctx) ctx = peers[0]; // fall back to earliest

    return {
      ...e,
      entity_type: e.entity_type || ctx.entity_type,
      entity_subtype: e.entity_subtype || ctx.entity_subtype,
      model: e.model || ctx.model,
      total_tokens: e.total_tokens != null ? e.total_tokens : ctx.total_tokens,
      session_turn_index: e.session_turn_index != null ? e.session_turn_index : ctx.session_turn_index,
      classification_signals: e.classification_signals || ctx.classification_signals,
      behavioral_alerts: e.behavioral_alerts || ctx.behavioral_alerts,
      caller_type_score: e.caller_type_score != null ? e.caller_type_score : ctx.caller_type_score
    };
  });
}
