// ─────────────── Master render ─────────────────────────────
function renderDashboard() {
  if (typeof appsmith === 'undefined' || !appsmith.model) return;
  const model = appsmith.model;
  allEvents = Array.isArray(model.events) ? enrichEvents(model.events) : [];
  updateHeaderStats();
  // Re-render whichever tab is active
  dispatchTab(currentTab);
}
function dispatchTab(idx) {
  switch (idx) {
    case 0:
      applyFilters();
      break;
    case 1:
      loadIdentityOverview();
      break;
    case 2:
      loadCallerSplit();
      break;
    case 3:
      loadRoleDistribution();
      break;
