      break;
    case 9:
      loadAgentTopology();
      break;
    case 10:
      loadRegulatoryStatus();
      break;
    case 11:
      loadEvasionReport();
      break;
  }
}

// ─────────────── Tab switching ─────────────────────────────
function switchTab(idx) {
  document.querySelectorAll('.tab-btn').forEach((b, i) => b.classList.toggle('active', i === idx));
  document.querySelectorAll('.panel').forEach((p, i) => p.classList.toggle('active', i === idx));
  currentTab = idx;
  dispatchTab(idx);
}

// ─────────────── Data aggregation helpers ─────────────────
// Group events by agent_id → per-agent aggregates used by many tabs
function inferAgentType(e) {
  if (e.agent_inferred_type) return e.agent_inferred_type;
  if (e.model && /claude|gpt|llama|mistral|gemini/i.test(e.model)) return 'LLM_AGENT';
  if (e.app_id) return 'APPLICATION';
  if (e.event_type === 'tool_call') return 'AUTOMATION';
  return 'UNKNOWN';
}
function aggregateAgents(events) {
  const byAgent = {};
  events.forEach(e => {
    if (!e.agent_id) return;
    const a = byAgent[e.agent_id] = byAgent[e.agent_id] || {
      agent_id: e.agent_id,
      display_name: e.agent_id.slice(0, 18),
      agent_type: inferAgentType(e),
      agent_role: e.agent_role || null,
      risk_level: e.agent_risk_level || null,
      primary_risk: e.agent_primary_risk || null,
      orchestration_role: e.orchestration_role || 'STANDALONE',
      first_seen_iso: e.timestamp_iso,
      last_seen_iso: e.timestamp_iso,
      call_count: 0,
      drift_scores: [],
      zasp_scores: [],
      drift_classifications: [],
      tools_called: new Set(),
      classification_signals: new Set(),
      behavioral_alerts: new Set(),
      iam_identity: null,
      latest_drift_score: 0,
      latest_drift_class: 'STABLE'
    };
    a.call_count++;
    if (e.drift_score != null) a.drift_scores.push(Number(e.drift_score));
    if (e.zasp_score != null) a.zasp_scores.push(Number(e.zasp_score));
    if (e.drift_classification) a.drift_classifications.push(e.drift_classification);
    if (e.tools_called) {
      String(e.tools_called).split('|').filter(Boolean).forEach(t => a.tools_called.add(t));
    }
    if (e.classification_signals) {
      String(e.classification_signals).split('|').filter(Boolean).forEach(s => a.classification_signals.add(s));
    }
    if (e.behavioral_alerts) {
      String(e.behavioral_alerts).split('|').filter(Boolean).forEach(s => a.behavioral_alerts.add(s));
    }
    if (e.timestamp_iso) {
      if (e.timestamp_iso < a.first_seen_iso) a.first_seen_iso = e.timestamp_iso;
      if (e.timestamp_iso > a.last_seen_iso) {
        a.last_seen_iso = e.timestamp_iso;
        a.latest_drift_score = Number(e.drift_score) || a.latest_drift_score;
        a.latest_drift_class = e.drift_classification || a.latest_drift_class;
      }
    }
  });
  // Finalize
  return Object.values(byAgent).map(a => {
    const driftScore = a.drift_scores.length ? a.drift_scores[a.drift_scores.length - 1] : 0;
    const meanZasp = a.zasp_scores.length ? a.zasp_scores.reduce((s, v) => s + v, 0) / a.zasp_scores.length : null;
    return {
      ...a,
      tools_called: Array.from(a.tools_called),
      classification_signals: Array.from(a.classification_signals),
      behavioral_alerts: Array.from(a.behavioral_alerts),
      drift_score: driftScore,
      drift_classification: a.latest_drift_class,
      mean_zasp: meanZasp,
      role_confidence: a.call_count > 10 ? 0.9 : a.call_count / 10
    };
  });
}

// ─────────────── Header stats ──────────────────────────────
function updateHeaderStats() {
  const total = allEvents.length;
  let human = 0,
    automated = 0,
    agent = 0,
    alerts = 0;
  const agentIds = new Set();
  allEvents.forEach(e => {
    if (e.entity_type === 'HUMAN') human++;else if (e.entity_type === 'AUTOMATED') automated++;else if (e.entity_type === 'AGENT') agent++;
    if (e.behavioral_alerts) alerts++;
    if (e.agent_id) agentIds.add(e.agent_id);
  });
  setText('hdr-total', total);
  setText('hdr-human', human);
  setText('hdr-auto', automated);
  setText('hdr-agent', agent);
  setText('hdr-alerts', alerts);
  setText('hdr-agents-known', agentIds.size);
}
function setText(id, v) {
  const el = document.getElementById(id);
  if (el) el.textContent = v;
}

// ─────────────── Tab 0: Event feed ─────────────────────────
function applyFilters() {
  const fEntity = val('f-entity');
  const fType = val('f-type');
  const fAlert = val('f-alert');
  const fSearch = (val('f-search') || '').toLowerCase();
  const filtered = allEvents.filter(e => {
    if (fEntity && e.entity_type !== fEntity) return false;
    if (fType && e.event_type !== fType) return false;
    if (fAlert && !(e.behavioral_alerts || '').includes(fAlert)) return false;
    if (fSearch && !JSON.stringify(e).toLowerCase().includes(fSearch)) return false;
    return true;
  });
  // Sort newest first
  filtered.sort((a, b) => {
    const ta = a.timestamp_ms || (a.timestamp_iso ? Date.parse(a.timestamp_iso) : 0);
    const tb = b.timestamp_ms || (b.timestamp_iso ? Date.parse(b.timestamp_iso) : 0);
    return tb - ta;
  });
  renderEventTable(filtered);
}
function val(id) {
  const el = document.getElementById(id);
  return el ? el.value : '';
}
