const CRIT_ALERTS = new Set(['REGULATORY_PROBE', 'PROGRESSIVE_PROBE', 'TAKEOVER_ALERT']);
function alertPills(raw) {
  if (!raw) return '—';
  return raw.split('|').map(a => `<span class="alert-pill${CRIT_ALERTS.has(a) ? ' critical' : ''}">${a}</span>`).join('');
