function signalPills(raw) {
  if (!raw) return '—';
  return raw.split('|').map(s => `<span class="signal-pill">${s}</span>`).join('');
}
function fmtTime(iso) {
  return iso ? iso.replace('T', ' ').replace('Z', '') : '—';
}
function renderEventTable(events) {
  const tbody = document.getElementById('events-body');
  if (!tbody) return;
  if (!events.length) {
    tbody.innerHTML = `<tr><td colspan="10"><div class="empty">No events match the current filters.</div></td></tr>`;
    return;
  }
  tbody.innerHTML = events.map(e => {
    const id = e.event_id || Math.random().toString(36).slice(2);
    return `
    <tr onclick="toggleDetail('${id}')" data-id="${id}">
      <td>${fmtTime(e.timestamp_iso)}</td>
      <td>${eventBadge(e.event_type)}</td>
      <td title="${esc(e.email || '')}">${esc((e.user_id || '—').substring(0, 14))}</td>
      <td>${entityBadge(e.entity_type)}${e.entity_subtype ? `<br/><span style="font-size:.62rem;color:#8b949e">${esc(e.entity_subtype)}</span>` : ''}</td>
      <td title="${esc(e.model || '')}">${esc((e.model || '—').replace('claude-', 'c-').replace('gpt-', 'g-'))}</td>
      <td>${e.latency_ms != null ? e.latency_ms + ' ms' : '—'}</td>
      <td>${e.total_tokens != null ? e.total_tokens : '—'}</td>
      <td style="text-align:center">${e.session_turn_index != null ? e.session_turn_index : '—'}</td>
      <td class="wrap">${signalPills(e.classification_signals)}</td>
      <td class="wrap">${alertPills(e.behavioral_alerts)}</td>
    </tr>
    <tr class="detail-row" id="detail-${id}" style="display:none">
      <td colspan="10"><div class="detail-box"><pre>${esc(JSON.stringify(e, null, 2))}</pre></div></td>
    </tr>`;
  }).join('');
}
function toggleDetail(id) {
  if (expandedId && expandedId !== id) {
    const prev = document.getElementById('detail-' + expandedId);
    if (prev) prev.style.display = 'none';
  }
  const row = document.getElementById('detail-' + id);
  if (!row) return;
  const visible = row.style.display !== 'none';
  row.style.display = visible ? 'none' : 'table-row';
  expandedId = visible ? null : id;
}
function toggleAutoRefresh() {
  // No-op in Appsmith mode: refresh is driven by onModelChange
}
function aggregateIdentities(events) {
  const byId = {};
  const rank = {
    UNKNOWN: 0,
    AUTOMATION: 1,
    APPLICATION: 2,
    HUMAN: 3,
    LLM_AGENT: 4
  };
  const inferType = e => {
    if (e.agent_inferred_type) return e.agent_inferred_type;
    if (e.entity_type === 'HUMAN') return 'HUMAN';
    if (e.model && /claude|gpt|llama|mistral|gemini/i.test(e.model)) return 'LLM_AGENT';
    if (e.entity_type === 'AUTOMATED') return 'AUTOMATION';
    if (e.app_id) return 'APPLICATION';
    return 'UNKNOWN';
  };
  events.forEach(e => {
    const id = e.agent_id || e.user_id || e.app_id;
    if (!id) return;
    const row = byId[id] = byId[id] || {
      identity_id: id,
      display_name: e.display_name || e.agent_id || e.user_id || e.app_id,
      agent_type: 'UNKNOWN',
      agent_role: e.agent_role || e.job_title || e.department || null,
      first_seen_iso: e.timestamp_iso,
      last_seen_iso: e.timestamp_iso,
      call_count: 0,
      drift_scores: [],
      drift_classification: 'STABLE',
      iam_identity: null,
      source: e.agent_id ? 'AGENT' : e.user_id ? 'USER' : 'APP'
    };

    // Upgrade type to strongest signal across all events
    const newType = inferType(e);
    if ((rank[newType] || 0) > (rank[row.agent_type] || 0)) {
      row.agent_type = newType;
    }

    // Fill in display_name/role if we now have better data
    if ((!row.display_name || /^unknown/i.test(row.display_name)) && e.display_name) {
      row.display_name = e.display_name;
    }
    if (!row.agent_role && (e.agent_role || e.job_title)) {
      row.agent_role = e.agent_role || e.job_title;
    }
    row.call_count++;
    if (e.drift_score != null) row.drift_scores.push(Number(e.drift_score));
    if (e.drift_classification) row.drift_classification = e.drift_classification;
    if (e.timestamp_iso) {
      if (e.timestamp_iso < row.first_seen_iso) row.first_seen_iso = e.timestamp_iso;
      if (e.timestamp_iso > row.last_seen_iso) row.last_seen_iso = e.timestamp_iso;
    }
  });
  return Object.values(byId).map(r => ({
    ...r,
    drift_score: r.drift_scores.length ? r.drift_scores[r.drift_scores.length - 1] : 0,
    role_confidence: r.call_count > 10 ? 0.9 : r.call_count / 10
  }));
}

