function loadIdentityOverview() {
  const tbody = document.getElementById('identity-body');
  if (!tbody) return;
  const rows = aggregateIdentities(allEvents);
  if (!rows.length) {
    tbody.innerHTML = '<tr><td colspan="10" class="empty">No identities observed yet.</td></tr>';
