      <td>${esc(a.agent_role || '—')}</td>
      <td>${pct(a.role_confidence)}</td>
      <td style="white-space:nowrap">${fmtTime(a.first_seen_iso)}</td>
      <td style="text-align:right">${a.call_count}</td>
