// ─────────────── Tab 6: Drift alerts ───────────────────────
function loadDriftAlerts() {
  const tbody = document.getElementById('alerts-body');
  if (!tbody) return;
  const agents = aggregateAgents(allEvents).filter(a => a.drift_classification && a.drift_classification !== 'STABLE' || a.behavioral_alerts.length).sort((a, b) => (b.drift_score || 0) - (a.drift_score || 0));
  if (!agents.length) {
    tbody.innerHTML = '<tr><td colspan="8" class="empty">No active drift alerts.</td></tr>';
    return;
  }
  tbody.innerHTML = agents.map(a => {
    const cls = a.drift_classification || 'STABLE';
    const rowCls = cls === 'CRITICAL' ? 'alert-row-critical' : cls === 'WARNING' ? 'alert-row-warning' : '';
    const primary = a.behavioral_alerts[0] || a.classification_signals[0] || '—';
    return `
      <tr class="${rowCls}">
        <td><span class="badge badge-${cls.toLowerCase()}">${cls}</span></td>
        <td><code style="font-size:.73rem">${esc(a.display_name || a.agent_id)}</code></td>
        <td>${esc(a.agent_role || '—')}</td>
        <td><span class="badge badge-${riskBadge(a.risk_level)}">${esc(a.risk_level || '—')}</span></td>
        <td style="text-align:right;font-weight:600">${(a.drift_score || 0).toFixed(4)}</td>
        <td><span class="alert-pill${cls === 'CRITICAL' ? ' critical' : ''}">${esc(primary)}</span></td>
        <td style="white-space:nowrap">${fmtTime(a.last_seen_iso)}</td>
        <td style="font-size:.75rem;max-width:280px">${esc(a.primary_risk || 'Review behavioral signals')}</td>
      </tr>`;
  }).join('');
}

// ─────────────── Tab 7: Benchmark coverage ─────────────────
function loadBenchmarkCoverage() {
  const agents = aggregateAgents(allEvents);
  const total = agents.length;
  const withBaseline = agents.filter(a => a.call_count >= 100 && a.zasp_scores.length > 0).length;
  const prelim = agents.filter(a => a.call_count < 100 && a.zasp_scores.length > 0).length;
  const none = agents.filter(a => a.zasp_scores.length === 0).length;
  const coverage = total ? Math.round(withBaseline / total * 100) : 0;
  const summary = document.getElementById('bench-summary');
  if (summary) summary.innerHTML = `
    <div class="card"><h3>Total Agents</h3><div class="big-num">${total}</div></div>
    <div class="card"><h3>ZASP Baseline</h3><div class="big-num" style="color:#3fb950">${withBaseline}</div><div class="sub">Coverage ${coverage}%</div></div>
    <div class="card"><h3>Preliminary Only</h3><div class="big-num" style="color:#d29922">${prelim}</div><div class="sub">&lt;100 calls</div></div>
    <div class="card"><h3>No Baseline</h3><div class="big-num" style="color:#f85149">${none}</div><div class="sub">lower drift sensitivity</div></div>`;

  // Coverage by role
  const byRole = {};
  agents.forEach(a => {
    const r = a.agent_role || 'Unknown';
    if (!byRole[r]) byRole[r] = {
      role: r,
      with_baseline: 0,
      total: 0
    };
    byRole[r].total++;
    if (a.call_count >= 100 && a.zasp_scores.length > 0) byRole[r].with_baseline++;
  });
  const arr = Object.values(byRole);
  if (arr.length) {
    rebuildChart('bench-chart', 'bar', {
      labels: arr.map(r => r.role),
      datasets: [{
        label: 'With ZASP baseline',
        data: arr.map(r => r.with_baseline),
        backgroundColor: '#3fb950cc',
        borderRadius: 3
      }, {
        label: 'Total',
        data: arr.map(r => r.total),
        backgroundColor: '#58a6ff44',
        borderRadius: 3
      }]
    }, {
      maintainAspectRatio: false,
      plugins: {
        legend: {
          labels: {
            boxWidth: 12,
            font: {
              size: 11
            }
          }
        }
      },
      scales: {
        y: {
          title: {
            display: true,
            text: 'Agents'
          }
        }
      }
    });
  }
}

