// ─────────────── Tab 8: IAM enrichment ─────────────────────
function loadIAMEnrichment() {
  const agents = aggregateAgents(allEvents);
  const matched = agents.filter(a => a.iam_identity);
  const pseudo = agents.length - matched.length;
  const enrichRate = agents.length ? Math.round(matched.length / agents.length * 100) : 0;

  // Treat literal "Unknown"/"unknown@domain.com"/empty as missing
  const clean = v => {
    if (v == null) return '';
    const s = String(v).trim();
    if (!s || /^unknown/i.test(s) || s === 'unknown@domain.com') return '';
    return s;
  };

  // Human callers — merge identity fields across all events for the same user_id,
  // preferring the first non-empty value found.
  const callersMap = {};
  allEvents.forEach(e => {
    if (!e.user_id) return;
    const incoming = {
      display_name: clean(e.display_name),
      email: clean(e.email),
      department: clean(e.department),
      job_title: clean(e.job_title),
      sailpoint_risk: clean(e.sailpoint_risk)
    };
    if (!callersMap[e.user_id]) {
      callersMap[e.user_id] = {
        user_id: e.user_id,
        ...incoming,
        call_count: 0,
        entity_counts: {}
      };
    } else {
      // Fill in any field that's still empty from a newly seen event
      const existing = callersMap[e.user_id];
      for (const k of ['display_name', 'email', 'department', 'job_title', 'sailpoint_risk']) {
        if (!existing[k] && incoming[k]) existing[k] = incoming[k];
      }
    }
    const c = callersMap[e.user_id];
    c.call_count++;
    const t = e.entity_type || 'UNKNOWN';
    c.entity_counts[t] = (c.entity_counts[t] || 0) + 1;
  });
  const callers = Object.values(callersMap).map(c => {
    const dom = Object.entries(c.entity_counts).sort((a, b) => b[1] - a[1])[0];
    return {
      ...c,
      dominant_entity: dom ? dom[0] : 'UNKNOWN'
    };
  });
  const metrics = document.getElementById('iam-metrics');
  if (metrics) metrics.innerHTML = `
    <div class="card"><div class="big-num">${agents.length}</div><div class="sub">Total Agents</div></div>
    <div class="card"><div class="big-num" style="color:#3fb950">${matched.length}</div><div class="sub">IAM Matched</div></div>
    <div class="card"><div class="big-num">${pseudo}</div><div class="sub">Pseudonymous</div></div>
    <div class="card"><div class="big-num" style="color:#58a6ff">${enrichRate}%</div><div class="sub">Enrichment Rate</div></div>
    <div class="card"><div class="big-num" style="font-size:.9rem;color:#8b949e">NO-IAM</div><div class="sub">IAM Mode</div></div>
    <div class="card"><div class="big-num">${callers.length}</div><div class="sub">Known Human Callers</div></div>`;
  rebuildChart('iam-pie', 'doughnut', {
    labels: ['IAM Matched', 'Pseudonymous'],
    datasets: [{
      data: [matched.length, pseudo],
      backgroundColor: ['#3fb950', '#8b949e'],
      borderWidth: 2,
      borderColor: '#f6f8fa'
    }]
  }, {
    plugins: {
      legend: {
        position: 'bottom',
        labels: {
          boxWidth: 12,
          font: {
            size: 11
          }
        }
      }
    },
    cutout: '55%'
  });
  const listEl = document.getElementById('iam-matched-list');
  if (listEl) {
    listEl.innerHTML = matched.length ? `<table style="width:100%;font-size:.78rem"><thead><tr><th>Agent ID</th><th>Name</th><th>Role</th><th>Risk</th><th>IAM Identity</th></tr></thead><tbody>
          ${matched.map(a => `<tr>
            <td><code style="font-size:.7rem">${esc(a.agent_id.slice(0, 20))}</code></td>
            <td>${esc(a.display_name || '—')}</td>
            <td>${esc(a.agent_role || '—')}</td>
            <td>${esc(a.risk_level || '—')}</td>
