function aggregateIdentities(events) {
  const byId = {};
  const rank = { UNKNOWN: 0, AUTOMATION: 1, APPLICATION: 2, HUMAN: 3, LLM_AGENT: 4 };

  const inferType = (e) => {
    if (e.agent_inferred_type) return e.agent_inferred_type;
    if (e.entity_type === 'HUMAN') return 'HUMAN';
    if (e.model && /claude|gpt|llama|mistral|gemini/i.test(e.model)) return 'LLM_AGENT';
    if (e.entity_type === 'AUTOMATED') return 'AUTOMATION';
    if (e.app_id) return 'APPLICATION';
    return 'UNKNOWN';
  };

  events.forEach(e => {
    const id = e.agent_id || e.user_id || e.app_id;
    if (!id) return;

    const row = byId[id] = byId[id] || {
      identity_id: id,
      display_name: e.display_name || e.agent_id || e.user_id || e.app_id,
      agent_type: 'UNKNOWN',
      agent_role: e.agent_role || e.job_title || e.department || null,
      first_seen_iso: e.timestamp_iso,
      last_seen_iso: e.timestamp_iso,
      call_count: 0,
      drift_scores: [],
      drift_classification: 'STABLE',
      iam_identity: null,
      source: e.agent_id ? 'AGENT' : (e.user_id ? 'USER' : 'APP'),
    };

    // Upgrade type to strongest signal across all events
    const newType = inferType(e);
    if ((rank[newType] || 0) > (rank[row.agent_type] || 0)) {
      row.agent_type = newType;
    }

    // Fill in display_name/role if we now have better data
    if ((!row.display_name || /^unknown/i.test(row.display_name)) && e.display_name) {
      row.display_name = e.display_name;
    }
    if (!row.agent_role && (e.agent_role || e.job_title)) {
      row.agent_role = e.agent_role || e.job_title;
    }

    row.call_count++;
    if (e.drift_score != null) row.drift_scores.push(Number(e.drift_score));
    if (e.drift_classification) row.drift_classification = e.drift_classification;
    if (e.timestamp_iso) {
      if (e.timestamp_iso < row.first_seen_iso) row.first_seen_iso = e.timestamp_iso;
      if (e.timestamp_iso > row.last_seen_iso)  row.last_seen_iso  = e.timestamp_iso;
    }
  });

  return Object.values(byId).map(r => ({
    ...r,
    drift_score: r.drift_scores.length ? r.drift_scores[r.drift_scores.length - 1] : 0,
    role_confidence: r.call_count > 10 ? 0.9 : r.call_count / 10,
  }));
}






