function loadDriftAlerts() {
  const tbody = document.getElementById('alerts-body');
  if (!tbody) return;
  const agents = aggregateAgents(allEvents)
    .filter(a => a.drift_classification && a.drift_classification !== 'STABLE' || a.behavioral_alerts.length)
    .sort((a, b) => (b.drift_score || 0) - (a.drift_score || 0));
  if (!agents.length) { tbody.innerHTML = '<tr><td colspan="8" class="empty">No active drift alerts.</td></tr>'; return; }
