// ─────────────── Tab 7: Benchmark coverage ─────────────────
function loadBenchmarkCoverage() {
  const agents = aggregateAgents(allEvents);
  const total = agents.length;
  const withBaseline = agents.filter(a => a.call_count >= 100 && a.zasp_scores.length > 0).length;
  const prelim = agents.filter(a => a.call_count < 100 && a.zasp_scores.length > 0).length;
  const none = agents.filter(a => a.zasp_scores.length === 0).length;
  const coverage = total ? Math.round((withBaseline / total) * 100) : 0;

  const summary = document.getElementById('bench-summary');
  if (summary) summary.innerHTML = `
    <div class="card"><h3>Total Agents</h3><div class="big-num">${total}</div></div>
    <div class="card"><h3>ZASP Baseline</h3><div class="big-num" style="color:#3fb950">${withBaseline}</div><div class="sub">Coverage ${coverage}%</div></div>
    <div class="card"><h3>Preliminary Only</h3><div class="big-num" style="color:#d29922">${prelim}</div><div class="sub">&lt;100 calls</div></div>
    <div class="card"><h3>No Baseline</h3><div class="big-num" style="color:#f85149">${none}</div><div class="sub">lower drift sensitivity</div></div>`;

  // Coverage by role
  const byRole = {};
  agents.forEach(a => {
    const r = a.agent_role || 'Unknown';
    if (!byRole[r]) byRole[r] = { role: r, with_baseline: 0, total: 0 };
    byRole[r].total++;
    if (a.call_count >= 100 && a.zasp_scores.length > 0) byRole[r].with_baseline++;
  });
  const arr = Object.values(byRole);
  if (arr.length) {
    rebuildChart('bench-chart', 'bar', {
      labels: arr.map(r => r.role),
      datasets: [
        { label: 'With ZASP baseline', data: arr.map(r => r.with_baseline), backgroundColor: '#3fb950cc', borderRadius: 3 },
        { label: 'Total', data: arr.map(r => r.total), backgroundColor: '#58a6ff44', borderRadius: 3 },
      ],
    }, { maintainAspectRatio: false, plugins: { legend: { labels: { boxWidth: 12, font: { size: 11 } } } }, scales: { y: { title: { display: true, text: 'Agents' } } } });
  }
}

// ─────────────── Tab 8: IAM enrichment ─────────────────────
// ─────────────── Tab 8: IAM enrichment ─────────────────────
function loadIAMEnrichment() {
  const agents = aggregateAgents(allEvents);
  const matched = agents.filter(a => a.iam_identity);
  const pseudo = agents.length - matched.length;
  const enrichRate = agents.length ? Math.round((matched.length / agents.length) * 100) : 0;

  // Treat literal "Unknown"/"unknown@domain.com"/empty as missing
  const clean = (v) => {
    if (v == null) return '';
    const s = String(v).trim();
    if (!s || /^unknown/i.test(s) || s === 'unknown@domain.com') return '';
    return s;
  };

  // Human callers — merge identity fields across all events for the same user_id,
  // preferring the first non-empty value found.
  const callersMap = {};
  allEvents.forEach(e => {
    if (!e.user_id) return;

    const incoming = {
      display_name:   clean(e.display_name),
      email:          clean(e.email),
      department:     clean(e.department),
      job_title:      clean(e.job_title),
      sailpoint_risk: clean(e.sailpoint_risk),
    };

    if (!callersMap[e.user_id]) {
      callersMap[e.user_id] = {
        user_id: e.user_id,
        ...incoming,
        call_count: 0,
        entity_counts: {},
      };
    } else {
      // Fill in any field that's still empty from a newly seen event
      const existing = callersMap[e.user_id];
      for (const k of ['display_name', 'email', 'department', 'job_title', 'sailpoint_risk']) {
        if (!existing[k] && incoming[k]) existing[k] = incoming[k];
      }
    }

    const c = callersMap[e.user_id];
    c.call_count++;
    const t = e.entity_type || 'UNKNOWN';
    c.entity_counts[t] = (c.entity_counts[t] || 0) + 1;
  });

  const callers = Object.values(callersMap).map(c => {
    const dom = Object.entries(c.entity_counts).sort((a, b) => b[1] - a[1])[0];
    return { ...c, dominant_entity: dom ? dom[0] : 'UNKNOWN' };
  });

  const metrics = document.getElementById('iam-metrics');
  if (metrics) metrics.innerHTML = `
    <div class="card"><div class="big-num">${agents.length}</div><div class="sub">Total Agents</div></div>
    <div class="card"><div class="big-num" style="color:#3fb950">${matched.length}</div><div class="sub">IAM Matched</div></div>
    <div class="card"><div class="big-num">${pseudo}</div><div class="sub">Pseudonymous</div></div>
    <div class="card"><div class="big-num" style="color:#58a6ff">${enrichRate}%</div><div class="sub">Enrichment Rate</div></div>
    <div class="card"><div class="big-num" style="font-size:.9rem;color:#8b949e">NO-IAM</div><div class="sub">IAM Mode</div></div>
    <div class="card"><div class="big-num">${callers.length}</div><div class="sub">Known Human Callers</div></div>`;

  rebuildChart('iam-pie', 'doughnut', {
    labels: ['IAM Matched', 'Pseudonymous'],
    datasets: [{ data: [matched.length, pseudo], backgroundColor: ['#3fb950', '#8b949e'], borderWidth: 2, borderColor: '#f6f8fa' }],
  }, { plugins: { legend: { position: 'bottom', labels: { boxWidth: 12, font: { size: 11 } } } }, cutout: '55%' });

  const listEl = document.getElementById('iam-matched-list');
  if (listEl) {
    listEl.innerHTML = matched.length
      ? `<table style="width:100%;font-size:.78rem"><thead><tr><th>Agent ID</th><th>Name</th><th>Role</th><th>Risk</th><th>IAM Identity</th></tr></thead><tbody>
          ${matched.map(a => `<tr>
            <td><code style="font-size:.7rem">${esc(a.agent_id.slice(0, 20))}</code></td>
            <td>${esc(a.display_name || '—')}</td>
            <td>${esc(a.agent_role || '—')}</td>
            <td>${esc(a.risk_level || '—')}</td>
            <td><span style="background:#f0fff4;color:#1a7f37;border:1px solid #a7f3d0;border-radius:4px;padding:2px 8px;font-size:.7rem">${esc(a.iam_identity)}</span></td>
          </tr>`).join('')}
        </tbody></table>`
      : '<div style="font-size:.8rem;color:#8b949e;padding:12px 0">No IAM-matched agents. Operating in pseudonymous mode.</div>';
  }

  const tbody = document.getElementById('iam-callers-body');
  if (tbody) {
    if (!callers.length) {
      tbody.innerHTML = '<tr><td colspan="7" style="text-align:center;color:#8b949e;padding:14px">No human caller data available.</td></tr>';
    } else {
      const riskColor = r => r >= 7 ? '#cf222e' : r >= 4 ? '#d29922' : '#3fb950';
      tbody.innerHTML = callers.map(c => {
        const risk = parseInt(c.sailpoint_risk) || 0;
        const etColor = c.dominant_entity === 'HUMAN' ? '#3fb950'
          : c.dominant_entity === 'AMBIGUOUS' ? '#d29922'
          : c.dominant_entity === 'AUTOMATED' ? '#8b949e' : '#58a6ff';
        return `<tr>
          <td style="font-weight:500">${esc(c.display_name || c.user_id)}</td>
          <td style="font-size:.75rem;color:#656d76">${esc(c.email || '—')}</td>
          <td style="font-size:.75rem">${esc(c.department || '—')}</td>
          <td style="font-size:.75rem">${esc(c.job_title || '—')}</td>
          <td><span style="color:${riskColor(risk)};font-weight:600">${esc(c.sailpoint_risk || '—')}</span></td>
          <td style="text-align:right;font-weight:600">${c.call_count}</td>
          <td><span style="background:${etColor}22;color:${etColor};border:1px solid ${etColor}44;border-radius:4px;padding:2px 7px;font-size:.7rem;font-weight:600">${esc(c.dominant_entity || '—')}</span></td>
        </tr>`;
      }).join('');
    }
  }
}


