// ─────────────── Tab 9: Agent topology ─────────────────────
const DRIFT_NODE_COLOR = {
  STABLE: '#3fb950', MONITOR: '#58a6ff', INVESTIGATE: '#f0883e', WARNING: '#d29922', CRITICAL: '#f85149',
};
function buildTopology(events) {
  const agents = aggregateAgents(events);
  const nodes = agents.map(a => {
    // Heuristic authority score from tool scope, role risk, and call volume
    const toolAuth = Math.min(1, a.tools_called.length / 5);
    const riskAuth = { CRITICAL: 1, HIGH: 0.8, MEDIUM: 0.5, LOW: 0.2 }[a.risk_level] || 0.3;
    const dataSens = a.classification_signals.some(s => s.includes('PII') || s.includes('CONFIDENTIAL')) ? 0.8 : 0.3;
    const authority = (toolAuth * 0.3 + riskAuth * 0.5 + dataSens * 0.2);
    return {
      agent_id: a.agent_id,
      display_name: a.display_name,
      agent_role: a.agent_role,
      orchestration_role: a.orchestration_role,
      authority_score: authority,
      authority_breakdown: { tool_scope: toolAuth, data_sens: dataSens },
      downstream_count: 0,
      drift_score: a.drift_score,
      drift_class: a.drift_classification,
      effective_drift_class: a.drift_classification,
      authority_escalated: authority > 0.7 && a.drift_classification === 'WARNING',
    };
  });
  return { nodes, edges: [], summary: {}, kill_chains: [], escalated_alerts: [] };
}
function loadAgentTopology() {
  const d = buildTopology(allEvents);
  const { nodes, edges } = d;

  const pills = document.getElementById('topo-summary-pills');
  if (pills) {
    pills.innerHTML = [
      ['Total Agents', nodes.length, '#1f2328'],
      ['High Authority', nodes.filter(n => n.authority_score >= 0.7).length, '#a40e26'],
      ['Escalated', nodes.filter(n => n.authority_escalated).length, '#d29922'],
      ['Kill Chain Paths', 0, '#0969da'],
      ['Edges', edges.length, '#656d76'],
    ].map(([label, val, color]) =>
      `<div style="background:#f6f8fa;border:1px solid #d0d7de;border-radius:6px;padding:7px 12px;text-align:center">
        <div style="font-size:1.2rem;font-weight:700;color:${color}">${val}</div>
        <div style="font-size:.68rem;color:#656d76;text-transform:uppercase;letter-spacing:.05em">${label}</div>
      </div>`
    ).join('');
  }

  renderTopologyCanvas(nodes, edges);

  const tbody = document.getElementById('topo-body');
  if (tbody) {
    if (!nodes.length) { tbody.innerHTML = '<tr><td colspan="10" class="empty">No agents observed yet.</td></tr>'; }
    else {
      tbody.innerHTML = [...nodes].sort((a, b) => b.authority_score - a.authority_score).map(n => {
        const authPct = Math.round((n.authority_score || 0) * 100);
        const authColor = authPct >= 70 ? '#a40e26' : authPct >= 50 ? '#d29922' : '#1a7f37';
        return `<tr>
          <td><code style="font-size:.73rem">${esc(n.display_name || n.agent_id)}</code></td>
          <td>${esc(n.agent_role || '—')}</td>
          <td><span class="badge badge-${orchBadge(n.orchestration_role)}">${esc(n.orchestration_role || '—')}</span></td>
          <td style="font-weight:700;color:${authColor}">${authPct}%</td>
          <td>${Math.round((n.authority_breakdown?.tool_scope || 0) * 100)}%</td>
          <td style="text-align:center">${n.downstream_count || 0}</td>
          <td>${Math.round((n.authority_breakdown?.data_sens || 0) * 100)}%</td>
          <td style="text-align:right">${n.drift_score != null ? n.drift_score.toFixed(3) : '—'}</td>
          <td><span class="badge badge-${(n.effective_drift_class || 'stable').toLowerCase()}">${n.effective_drift_class || '—'}</span></td>
          <td style="text-align:center">${n.authority_escalated ? '<span style="color:#f85149;font-size:.8rem;font-weight:700">⬆ YES</span>' : '<span style="color:#8b949e;font-size:.75rem">—</span>'}</td>
        </tr>`;
      }).join('');
    }
  }

  const kc = document.getElementById('kill-chain-list');
  if (kc) kc.innerHTML = '<div style="font-size:.82rem;color:#656d76;padding:12px;background:#f6f8fa;border:1px solid #d0d7de;border-radius:6px">Kill chain analysis requires multi-agent edge data not present in this dataset.</div>';

  const esca = document.getElementById('escalated-alerts-body');
  if (esca) esca.innerHTML = '<tr><td colspan="6" class="empty">No escalated alerts.</td></tr>';
}
function renderTopologyCanvas(nodes, edges) {
  const canvas = document.getElementById('topology-canvas');
  if (!canvas) return;
  const ctx = canvas.getContext('2d');
  const W = Math.max(canvas.offsetWidth || 700, 500);
  const H = 420;
  canvas.width = W; canvas.height = H;
  ctx.clearRect(0, 0, W, H);
  if (!nodes.length) {
    ctx.fillStyle = '#8b949e';
    ctx.font = '14px Segoe UI, system-ui, sans-serif';
    ctx.textAlign = 'center';
    ctx.fillText('No agents observed yet.', W / 2, H / 2);
    return;
  }
  const cx = W / 2, cy = H / 2;
  const pos = {};
  nodes.forEach((n, i) => {
    const angle = (2 * Math.PI * i) / nodes.length - Math.PI / 2;
    const r = Math.min(W, H) * 0.30;
    pos[n.agent_id] = { x: cx + r * Math.cos(angle), y: cy + r * Math.sin(angle), vx: 0, vy: 0 };
  });
  for (let iter = 0; iter < 80; iter++) {
    for (let i = 0; i < nodes.length; i++) {
      for (let j = i + 1; j < nodes.length; j++) {
        const pi = pos[nodes[i].agent_id], pj = pos[nodes[j].agent_id];
        const dx = pi.x - pj.x, dy = pi.y - pj.y;
        const dist = Math.max(Math.sqrt(dx * dx + dy * dy), 1);
        const force = 4500 / (dist * dist);
        const fx = force * dx / dist, fy = force * dy / dist;
        pi.vx += fx; pi.vy += fy; pj.vx -= fx; pj.vy -= fy;
      }
    }
    edges.forEach(e => {
      const ps = pos[e.source], pt = pos[e.target];
      if (!ps || !pt) return;
      const dx = pt.x - ps.x, dy = pt.y - ps.y;
      const dist = Math.max(Math.sqrt(dx * dx + dy * dy), 1);
      const ideal = 140 + (e.confidence || 0.5) * 60;
      const spring = (dist - ideal) * 0.04;
      ps.vx += spring * dx / dist; ps.vy += spring * dy / dist;
      pt.vx -= spring * dx / dist; pt.vy -= spring * dy / dist;
    });
    nodes.forEach(n => {
      const p = pos[n.agent_id];
      p.vx += (cx - p.x) * 0.012; p.vy += (cy - p.y) * 0.012;
      p.vx *= 0.78; p.vy *= 0.78;
      p.x = Math.max(45, Math.min(W - 45, p.x + p.vx));
      p.y = Math.max(45, Math.min(H - 45, p.y + p.vy));
    });
  }
  edges.forEach(e => {
    const ps = pos[e.source], pt = pos[e.target];
    if (!ps || !pt) return;
    ctx.strokeStyle = `rgba(139,148,158,0.5)`;
    ctx.lineWidth = 2;
    ctx.beginPath(); ctx.moveTo(ps.x, ps.y); ctx.lineTo(pt.x, pt.y); ctx.stroke();
  });
  nodes.forEach(n => {
    const p = pos[n.agent_id];
    const nr = 14 + (n.authority_score || 0) * 22;
    const dc = n.effective_drift_class || n.drift_class || 'STABLE';
    const fillColor = DRIFT_NODE_COLOR[dc] || '#8b949e';
    if (n.authority_escalated) {
      ctx.beginPath(); ctx.arc(p.x, p.y, nr + 5, 0, 2 * Math.PI);
      ctx.strokeStyle = '#f85149'; ctx.lineWidth = 2.5; ctx.setLineDash([4, 3]); ctx.stroke(); ctx.setLineDash([]);
    }
    ctx.beginPath(); ctx.arc(p.x, p.y, nr, 0, 2 * Math.PI);
    ctx.fillStyle = fillColor; ctx.fill();
    ctx.strokeStyle = '#fff'; ctx.lineWidth = 2; ctx.stroke();
    ctx.fillStyle = '#fff';
    ctx.font = `bold ${Math.max(9, Math.round(nr * 0.38))}px Segoe UI, sans-serif`;
    ctx.textAlign = 'center'; ctx.textBaseline = 'middle';
    const label = (n.display_name || n.agent_id).substring(0, 11);
    ctx.fillText(label, p.x, p.y - 4);
    ctx.font = `${Math.max(8, Math.round(nr * 0.3))}px Segoe UI, sans-serif`;
    ctx.fillStyle = 'rgba(255,255,255,0.85)';
    ctx.fillText(`${Math.round((n.authority_score || 0) * 100)}%`, p.x, p.y + 7);
  });
}

// ─────────────── Tab 10: Regulatory ────────────────────────
function loadRegulatoryStatus() {
  const agents = aggregateAgents(allEvents);
  const frameworks = ['EU AI Act', 'SR 11-7', 'NIST AI RMF', 'FFIEC', 'ISO 42001'];
  // Simple heuristic: agent is SATISFIED if it has baseline (100+ calls) + zasp scores + no critical alerts
  const evaluate = a => {
    if (a.behavioral_alerts.some(x => CRIT_ALERTS.has(x))) return 'GAP';
    if (a.call_count >= 100 && a.zasp_scores.length > 0) return 'SATISFIED';
    if (a.zasp_scores.length > 0) return 'PARTIAL';
    return 'GAP';
  };
  const agentRows = agents.map(a => {
    const status = evaluate(a);
    const byFw = {};
    frameworks.forEach(fw => byFw[fw] = status);
    return {
      agent_id: a.agent_id,
      display_name: a.display_name,
      agent_role: a.agent_role,
      call_count: a.call_count,
      overall_status: status,
      coverage_pct: status === 'SATISFIED' ? 100 : status === 'PARTIAL' ? 50 : 0,
      by_framework: byFw,
    };
  });
  const satisfied = agentRows.filter(a => a.overall_status === 'SATISFIED').length;
  const overallCov = agentRows.length ? Math.round((satisfied / agentRows.length) * 100) : 0;
  const gaps = {};
  frameworks.forEach(fw => {
    const gap = agentRows.some(a => a.by_framework[fw] === 'GAP');
    if (gap) gaps[fw] = true;
  });

  const summary = document.getElementById('reg-summary');
  if (summary) summary.innerHTML = `
    <div class="card"><h3>Total Agents</h3><div class="big-num">${agentRows.length}</div></div>
    <div class="card"><h3>Fully Satisfied</h3><div class="big-num" style="color:#1a7f37">${satisfied}</div><div class="sub">${overallCov}% coverage</div></div>
    <div class="card"><h3>Framework Gaps</h3><div class="big-num" style="color:#a40e26">${Object.keys(gaps).length}</div><div class="sub">${Object.keys(gaps).join(', ') || 'None'}</div></div>`;

  const fwEl = document.getElementById('fw-status-row');
  if (fwEl) {
    fwEl.innerHTML = frameworks.map(fw => {
      const gapCount = agentRows.filter(a => a.by_framework[fw] === 'GAP').length;
      const worst = gapCount > 0 ? 'GAP' : agentRows.some(a => a.by_framework[fw] === 'PARTIAL') ? 'PARTIAL' : 'SATISFIED';
      const c = STATUS_COLOR_MAP[worst] || STATUS_COLOR_MAP['N/A'];
      return `<div style="background:${c.bg};border:1px solid ${c.fg}44;border-radius:8px;padding:10px 16px;min-width:160px">
        <div style="font-size:.68rem;color:${c.fg};font-weight:600;text-transform:uppercase;letter-spacing:.05em;margin-bottom:4px">${esc(fw)}</div>
        <div style="font-size:1.0rem;font-weight:700;color:${c.fg}">${worst}</div>
        ${gapCount > 0 ? `<div style="font-size:.7rem;color:${c.fg};margin-top:2px">${gapCount} agent gap(s)</div>` : ''}
      </div>`;
    }).join('');
  }

  const thead = document.getElementById('reg-matrix-head');
  const tbody = document.getElementById('reg-matrix-body');
  if (thead) thead.innerHTML = `<tr>
    <th>Agent</th><th>Role</th><th>Calls</th><th>Overall</th><th>Coverage</th>
    ${frameworks.map(fw => `<th>${esc(fw)}</th>`).join('')}
  </tr>`;
  if (tbody) {
    if (!agentRows.length) {
      tbody.innerHTML = '<tr><td colspan="10" class="empty">No agents observed yet.</td></tr>';
    } else {
      tbody.innerHTML = agentRows.map(a => `
        <tr>
          <td><code style="font-size:.73rem">${esc(a.display_name || a.agent_id)}</code></td>
          <td>${esc(a.agent_role || '—')}</td>
          <td style="text-align:right">${a.call_count}</td>
          <td>${statusBadge(a.overall_status)}</td>
          <td style="text-align:right">${a.coverage_pct}%</td>
          ${frameworks.map(fw => `<td>${statusBadge(a.by_framework[fw])}</td>`).join('')}
        </tr>`).join('');
    }
  }

  const area = document.getElementById('req-detail-area');
  if (area) area.innerHTML = '';
}
const STATUS_COLOR_MAP = {
  SATISFIED: { bg: '#dafbe1', fg: '#116329' },
  PARTIAL: { bg: '#fff8c5', fg: '#7d4e00' },
  GAP: { bg: '#ffebe9', fg: '#a40e26' },
  'N/A': { bg: '#f0f0f0', fg: '#656d76' },
};
function statusBadge(s) {
  const c = STATUS_COLOR_MAP[s] || STATUS_COLOR_MAP['N/A'];
  return `<span style="display:inline-block;padding:2px 9px;border-radius:20px;font-size:.7rem;font-weight:700;background:${c.bg};color:${c.fg}">${s || '—'}</span>`;
}
